import{c as e,Q as t,j as i,m as r}from"./chunks/framework.DVkeSyfh.js";const p=JSON.parse('{"title":"Документация dj-track-similarity","description":"","frontmatter":{},"headers":[],"relativePath":"ru/project-guide.md","filePath":"ru/project-guide.md","lastUpdated":1780038170000}'),l={name:"ru/project-guide.md"};function h(d,a,o,s,c,m){return t(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="документация-dj-track-similarity" tabindex="-1">Документация dj-track-similarity <a class="header-anchor" href="#документация-dj-track-similarity" aria-label="Permalink to &quot;Документация dj-track-similarity&quot;">​</a></h1><p>Это индекс документации <code>dj-track-similarity</code>. Начинайте отсюда, если не уверены, какая страница нужна. Краткое введение остается в <a href="https://github.com/MeteorBurn/dj-track-similarity/blob/main/README.md" target="_blank" rel="noreferrer">README репозитория</a>; страницы ниже содержат пользовательские и разработческие справочники.</p><p>Русская локализация переводит текущую пользовательскую документацию. Английская версия остается канонической для регулярных обновлений UI-документации; русская версия обновляется по отдельному запросу.</p><p>Для первого локального запуска начните с раздела <a href="./install.html">Установка</a>, прочитайте <a href="./overview.html">Обзор</a>, затем используйте <a href="./cli.html">CLI</a>, чтобы просканировать папку и запустить сервер. Если база библиотеки уже есть, откройте <a href="./analysis.html">Анализ</a>, чтобы выбрать следующий проход анализа, а затем <a href="./search-and-tags.html">Поиск и теги</a> для ежедневного DJ-рабочего процесса.</p><h2 id="основнои-проект" tabindex="-1">Основной проект <a class="header-anchor" href="#основнои-проект" aria-label="Permalink to &quot;Основной проект&quot;">​</a></h2><ul><li><a href="./install.html">Установка</a>: требования, группы зависимостей, проверенный Windows CUDA-стек, настройка FFmpeg и проверка установки.</li><li><a href="./overview.html">Обзор</a>: назначение проекта, ключевые возможности, модель безопасности и поддерживаемые аудиофайлы.</li><li><a href="./architecture.html">Архитектура</a>: карта backend/frontend, зависимости, заметки по CUDA/FFmpeg и логирование. Используйте, когда неясны установка, GPU, декодирование аудио или запуск сервера.</li><li><a href="./database.html">База данных</a>: схема SQLite, метаданные, embeddings и хранилище оценок классификаторов. Используйте, чтобы понять, что приложение сохраняет и что остается только для чтения.</li><li><a href="./models.html">Модели</a>: что такое каждая модель (Sonara, MAEST, MERT, CLAP), что она выдаёт, как её использует приложение и какие группы зависимостей ей нужны.</li><li><a href="./analysis.html">Анализ</a>: Sonara, MAEST, MERT, CLAP и оценка продвинутыми классификаторами. Используйте перед долгими задачами анализа, чтобы выбрать нужное семейство признаков.</li><li><a href="./search-and-tags.html">Поиск и теги</a>: рабочие процессы SONARA/MERT/CLAP/CLASS и запись стандартных жанров. Используйте для поиска совместимых треков, фильтрации по классификаторам и решения, когда безопасно записывать жанры.</li><li><a href="./cli.html">CLI</a>: команды <code>dj-sim</code>, параметры, вывод и примеры.</li><li><a href="./api.html">Web API</a>: FastAPI endpoints, которые использует frontend.</li><li><a href="./development.html">Разработка</a>: команды настройки и рекомендации по фокусной проверке.</li></ul><h2 id="rhythm-lab" tabindex="-1">Rhythm Lab <a class="header-anchor" href="#rhythm-lab" aria-label="Permalink to &quot;Rhythm Lab&quot;">​</a></h2><ul><li><a href="./rhythm-lab.html">Rhythm Lab</a>: профили классификаторов, UI разметки, обучение, предсказания, promotion, удаление и интеграция с основным приложением.</li></ul><h2 id="служебные-скрипты" tabindex="-1">Служебные скрипты <a class="header-anchor" href="#служебные-скрипты" aria-label="Permalink to &quot;Служебные скрипты&quot;">​</a></h2><p>Здесь документируются только стабильные пользовательские помощники:</p><ul><li><p>Остальные Python-файлы в <code>scripts/</code> являются разовыми диагностиками, миграциями или экспериментами. Для них источником истины остаются локальный вывод <code>--help</code> и фокусные тесты, а не публичный maintenance guide.</p></li><li><p><a href="./scripts/repair-audio-metadata.html">Восстановление метаданных</a>: диагностика и восстановление метаданных/контейнеров с dry-run по умолчанию.</p></li><li><p><a href="./scripts/audio-dedup.html">Дубли и очистка</a>: по умолчанию только отчётный анализ кандидатов на дубли, плюс явный подтверждаемый проход очистки <code>--apply</code>.</p></li><li><p><a href="./scripts/optimize-database.html">Оптимизация БД</a>: проверенная по схеме резервная копия SQLite, <code>VACUUM</code>, <code>ANALYZE</code> и проверка целостности.</p></li></ul>',11)])])}const f=e(l,[["render",h]]);export{p as __pageData,f as default};
